// Generates src/lib/brandIconData.ts — a curated, OFFLINE subset of Iconify
// brand logos (plan 27, pattern borrowed from Faro's plan 14). Only the
// handful of marks LocalKit actually renders are extracted from the full
// @iconify-json/simple-icons set, so the app bundles ~1 KB of icon data and
// makes ZERO network calls (nothing ever hits api.iconify.design).
//
// Run `npm run gen:brand-icons` after adding an icon to CURATED below. The
// @iconify-json/* packages + @iconify/utils are devDependencies used only
// here; the generated file is committed so normal builds don't need them.
//
// Licence: simple-icons is CC0-1.0.

import { getIconData } from "@iconify/utils";
import { writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import path from "node:path";

import simpleIcons from "@iconify-json/simple-icons/icons.json" with { type: "json" };

const SET = simpleIcons.default ?? simpleIcons;

// Every brand mark LocalKit renders, keyed by simple-icons name.
// kindIcon() in src/lib/brandIcons.tsx maps a site kind onto one of these.
const CURATED = [
  "wordpress", // kind: wordpress
  "docker", // kind: docker
  "php", // kind: php
  "laravel", // php-kind Laravel skeletons (New Site dialog, future)
  "mariadb", // database panels (future)
];

// Drop transformation fields that equal the Iconify defaults, to keep the
// generated file tiny and readable.
function trim(data) {
  const out = { body: data.body, width: data.width, height: data.height };
  if (data.left) out.left = data.left;
  if (data.top) out.top = data.top;
  if (data.rotate) out.rotate = data.rotate;
  if (data.hFlip) out.hFlip = true;
  if (data.vFlip) out.vFlip = true;
  return out;
}

const entries = [];
const missing = [];
for (const name of CURATED) {
  const data = getIconData(SET, name);
  if (!data) {
    missing.push(name);
    continue;
  }
  entries.push([name, trim(data)]);
}

if (missing.length) {
  console.error("gen-brand-icons: icons not found in @iconify-json/simple-icons:");
  for (const m of missing) console.error("  - " + m);
  process.exit(1);
}

const header = `// AUTO-GENERATED by scripts/gen-brand-icons.mjs — DO NOT EDIT BY HAND.
// A curated, offline subset of simple-icons brand logos (plan 27). Regenerate
// with \`npm run gen:brand-icons\` after editing CURATED in that script.
// Licence: simple-icons = CC0-1.0.
import type { IconifyIcon } from "@iconify/react/offline";
`;

const lines = entries.map(
  ([name, data]) => `  ${JSON.stringify(name)}: ${JSON.stringify(data)},`
);
const body = `\nexport const BRAND_ICONS: Record<string, IconifyIcon> = {\n${lines.join(
  "\n"
)}\n};\n`;

const outPath = path.resolve(
  path.dirname(fileURLToPath(import.meta.url)),
  "..",
  "src",
  "lib",
  "brandIconData.ts"
);
writeFileSync(outPath, header + body);

const bytes = Buffer.byteLength(header + body);
console.log(
  `gen-brand-icons: wrote ${entries.length} icons → src/lib/brandIconData.ts (${(
    bytes / 1024
  ).toFixed(1)} KB)`
);
